/**
 * Shell-specific completion script content and install paths.
 *
 * Each script delegates to `pragma completions <shell>` at runtime
 * so the completion logic stays in the CLI, not in the shell script.
 */

import type { ShellId } from "./detectShell.js";

const HOME = process.env.HOME ?? "";

/**
 * Generate the completion script content for a shell.
 */
export function completionScriptContent(shell: ShellId): string {
  switch (shell) {
    case "zsh":
      return [
        "#compdef pragma",
        "# Generated by `pragma setup completions`",
        "",
        "_pragma() {",
        "  local -a completions",
        // biome-ignore lint/suspicious/noTemplateCurlyInString: shell syntax, not JS template
        '  completions=("${(@f)$(pragma completions zsh -- "${words[@]}" 2>/dev/null)}")',
        "  compadd -- $completions",
        "}",
        "",
        "compdef _pragma pragma",
        "",
      ].join("\n");

    case "bash":
      return [
        "# Generated by `pragma setup completions`",
        "",
        "_pragma() {",
        // biome-ignore lint/suspicious/noTemplateCurlyInString: shell syntax, not JS template
        '  local cur="${COMP_WORDS[COMP_CWORD]}"',
        "  local completions",
        // biome-ignore lint/suspicious/noTemplateCurlyInString: shell syntax, not JS template
        '  completions=$(pragma completions bash -- "${COMP_WORDS[@]}" 2>/dev/null)',
        "  # shellcheck disable=SC2207",
        '  COMPREPLY=($(compgen -W "$completions" -- "$cur"))',
        "}",
        "",
        "complete -F _pragma pragma",
        "",
      ].join("\n");

    case "fish":
      return [
        "# Generated by `pragma setup completions`",
        "",
        "complete -c pragma -f -a '(pragma completions fish -- (commandline -cop) 2>/dev/null)'",
        "",
      ].join("\n");
  }
}

/**
 * Standard install path for a shell's completion script.
 */
export function completionScriptPath(shell: ShellId): string {
  switch (shell) {
    case "zsh":
      return `${HOME}/.zfunc/_pragma`;
    case "bash":
      return `${HOME}/.local/share/bash-completion/completions/pragma`;
    case "fish":
      return `${HOME}/.config/fish/completions/pragma.fish`;
  }
}

/**
 * Post-install hint shown to the user after completion setup.
 */
export function postInstallHint(shell: ShellId): string {
  switch (shell) {
    case "zsh":
      return "Run `source ~/.zshrc` or start a new shell to activate.";
    case "bash":
      return "Run `source ~/.bashrc` or start a new shell to activate.";
    case "fish":
      return "Start a new shell to activate.";
  }
}
